const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremium = (item: Item): number => {
  if (item.type === "sword") return 100;
  return 0;
};

const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);

const itemPremium = (item: Item): number =>
  basePremium(item) * (1 + FIRST_INSURANCE_SURCHARGE);

const quotePremium = (items: Item[]): number => {
  const itemTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
  return roundUp(itemTotal + PROCESSING_FEE);
};
